export const largestPrime = (num = 600851475143) => {
  let newnum = num
  let largestFact = 0
  let counter = 2
  while (counter * counter <= newnum) {
    if (newnum % counter === 0) {
      newnum = newnum / counter
    } else {
      counter++
    }
