/**
 * Problem 19 - Counting Sundays
 *
 * @see {@link https://projecteuler.net/problem=19}
 *
 * You are given the following information, but you may prefer to do some research for yourself.
 * 1 Jan 1900 was a Monday.
 * Thirty days has September,
 * April, June and November.
 * All the rest have thirty-one,
 * Saving February alone,
 * Which has twenty-eight, rain or shine.
 * And on leap years, twenty-nine.
 * A leap year occurs on any year evenly divisible by 4, but not on a century unless it is divisible by 400.
 * How many Sundays fell on the first of the month during the twentieth century (1 Jan 1901 to 31 Dec 2000)?
 *
 * @author ddaniel27
 */
import { isLeapYear } from '../Maths/LeapYear'

function problem19() {
  let sundaysCount = 0 // Count of Sundays
  let dayOfWeek = 2 // 1st Jan 1900 was a Monday, so 1st Jan 1901 was a Tuesday

  for (let year = 1901; year <= 2000; year++) {
    for (let month = 1; month <= 12; month++) {
      if (dayOfWeek === 0) {
        // If it's a Sunday (0 is Sunday, 1 is Monday, ..., 6 is Saturday)
        sundaysCount++
      }

      let daysInMonth = 31
      if (month === 4 || month === 6 || month === 9 || month === 11) {
        // April, June, September, November
        daysInMonth = 30
      } else if (month === 2) {
        // February
        daysInMonth = isLeapYear(year) ? 29 : 28
      }

      dayOfWeek = (dayOfWeek + daysInMonth) % 7 // Calculate the day of the week
    }
  }

  return sundaysCount
}

export { problem19 }

Project-Euler/Problem020.js.content:
/**
 * Problem 20 - Factorial digit sum
 *
 * @see {@link https://projecteuler.net/problem=20}
 *
 * n! means n × (n − 1) × ... × 3 × 2 × 1
 *
 * For example, 10! = 10 × 9 × ... × 3 × 2 × 1 = 3628800,
 * and the sum of the digits in the number 10! is 3 + 6 + 2 + 8 + 8 + 0 + 0 = 27
 *
 * Find the sum of the digits in the number 100!
 */

const factorialDigitSum = (n = 100) => {
  // Consider each digit*10^exp separately, right-to-left ([units, tens, ...]).
  const digits = [1]

  for (let x = 2; x <= n; x++) {
    let carry = 0
    for (let exp = 0; exp < digits.length; exp++) {
      const prod = digits[exp] * x + carry
      carry = Math.floor(prod / 10)
      digits[exp] = prod % 10
    }
    while (carry > 0) {
      digits.push(carry % 10)
      carry = Math.floor(carry / 10)
    }
  }

  // (digits are reversed but we only want the sum so it doesn't matter)

  return digits.reduce((prev, current) => prev + current, 0)
}

export { factorialDigitSum }

